class InMemoryItemService {

    private static final Logger log = LoggerFactory.getLogger(InMemoryItemService.class);
    private final List<ItemResponse> items = new CopyOnWriteArrayList<>();

    public List<ItemResponse> getAll() {
        log.debug("Retrieving all items from in-memory store");
        return List.copyOf(items);
    }

    public java.util.Optional<ItemResponse> getById(String id) {
        log.debug("Retrieving item from in-memory store by id={}", id);
        return items.stream().filter(item -> item.id().equals(id)).findFirst();
    }

    public ItemResponse create(CreateItemRequest request) {
        String id = UUID.randomUUID().toString();
        ItemResponse item = new ItemResponse(id, request.name(), request.description(), Instant.now().toString());
        items.add(item);
        log.debug("Item stored successfully with id={}", id);
        return item;
    }
}

